package com.example.networking.interceptor

import com.example.networking.auth.TokenProvider
import okhttp3.Authenticator
import okhttp3.Request
import okhttp3.Response
import okhttp3.Route

class TokenAuthenticator(private val tokenProvider: TokenProvider) : Authenticator {

    override fun authenticate(route: Route?, response: Response): Request? {
        // Prevent infinite retry loops
        if (responseCount(response) >= 2) {
            tokenProvider.clearTokens()
            return null
        }

        // Here you would typically call a refresh token endpoint synchronously
        // For simplicity, we clear tokens and return null to signal auth failure
        val refreshToken = tokenProvider.getRefreshToken()
        if (refreshToken == null) {
            tokenProvider.clearTokens()
            return null
        }

        // TODO: Implement actual token refresh call here
        // val newToken = refreshTokenSync(refreshToken)
        // tokenProvider.saveAccessToken(newToken)

        val newAccessToken = tokenProvider.getAccessToken() ?: return null

        return response.request.newBuilder()
            .header("Authorization", "Bearer $newAccessToken")
            .build()
    }

    private fun responseCount(response: Response): Int {
        var count = 1
        var priorResponse = response.priorResponse
        while (priorResponse != null) {
            count++
            priorResponse = priorResponse.priorResponse
        }
        return count
    }
}

