package com.example.networking.security

import com.example.networking.Environment
import okhttp3.CertificatePinner

object CertificatePinnerConfig {

    fun create(environment: Environment): CertificatePinner {
        val builder = CertificatePinner.Builder()

        when (environment) {
            Environment.DEV -> {
                builder.add(
                    "dev-api.example.com",
                    "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA="  // Replace with actual pin
                )
            }
            Environment.STAGING -> {
                builder.add(
                    "staging-api.example.com",
                    "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="  // Replace with actual pin
                )
            }
            Environment.PRODUCTION -> {
                builder.add(
                    "api.example.com",
                    "sha256/CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC=",  // Primary pin
                    "sha256/DDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDD="   // Backup pin
                )
            }
        }

        return builder.build()
    }
}

