package com.example.networking

import com.example.networking.api.UserApiService
import com.example.networking.auth.TokenProvider
import com.example.networking.interceptor.AuthInterceptor
import com.example.networking.interceptor.TokenAuthenticator
import com.example.networking.security.CertificatePinnerConfig
import okhttp3.ConnectionSpec
import okhttp3.OkHttpClient
import okhttp3.TlsVersion
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private var retrofit: Retrofit? = null
    private var environment: Environment = Environment.DEV
    private var tokenProvider: TokenProvider? = null

    fun init(env: Environment, provider: TokenProvider) {
        environment = env
        tokenProvider = provider
        retrofit = null // Reset so it rebuilds with new config
    }

    private fun getOkHttpClient(): OkHttpClient {
        val provider = tokenProvider
            ?: throw IllegalStateException("TokenProvider not initialized. Call NetworkModule.init() first.")

        // Enforce TLS 1.2+ only - prevent insecure transport
        val tlsSpec = ConnectionSpec.Builder(ConnectionSpec.MODERN_TLS)
            .tlsVersions(TlsVersion.TLS_1_2, TlsVersion.TLS_1_3)
            .build()

        val connectionSpecs = listOf(tlsSpec)

        // Logging interceptor - only verbose in dev
        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = when (environment) {
                Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                Environment.STAGING -> HttpLoggingInterceptor.Level.BASIC
                Environment.PRODUCTION -> HttpLoggingInterceptor.Level.NONE
            }
        }

        // Certificate pinning
        val certificatePinner = CertificatePinnerConfig.create(environment)

        return OkHttpClient.Builder()
            .connectionSpecs(connectionSpecs)
            .certificatePinner(certificatePinner)
            .addInterceptor(AuthInterceptor(provider))
            .addInterceptor(loggingInterceptor)
            .authenticator(TokenAuthenticator(provider))
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            // Do NOT use .hostnameVerifier that accepts all hostnames
            // Do NOT use custom TrustManagers that trust all certificates
            .followSslRedirects(true)
            .followRedirects(false) // Prevent redirect to HTTP
            .build()
    }

    private fun getRetrofit(): Retrofit {
        return retrofit ?: synchronized(this) {
            retrofit ?: Retrofit.Builder()
                .baseUrl(environment.baseUrl)
                .client(getOkHttpClient())
                .addConverterFactory(GsonConverterFactory.create())
                .build()
                .also { retrofit = it }
        }
    }

    fun getUserApiService(): UserApiService {
        return getRetrofit().create(UserApiService::class.java)
    }
}

