package com.example.networking.repository

import com.example.networking.ApiResult
import com.example.networking.NetworkModule
import com.example.networking.model.UserProfile
import com.example.networking.model.UserProfileResponse
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import retrofit2.Response

class UserRepository {

    private val apiService = NetworkModule.getUserApiService()

    suspend fun getUsers(page: Int = 1, limit: Int = 20): ApiResult<UserProfileResponse> {
        return safeApiCall { apiService.getUsers(page, limit) }
    }

    suspend fun getUserById(id: Long): ApiResult<UserProfile> {
        return safeApiCall { apiService.getUserById(id) }
    }

    suspend fun getCurrentUser(): ApiResult<UserProfile> {
        return safeApiCall { apiService.getCurrentUser() }
    }

    suspend fun searchUsers(query: String, page: Int = 1, limit: Int = 20): ApiResult<UserProfileResponse> {
        return safeApiCall { apiService.searchUsers(query, page, limit) }
    }

    private suspend fun <T> safeApiCall(apiCall: suspend () -> Response<T>): ApiResult<T> {
        return withContext(Dispatchers.IO) {
            try {
                val response = apiCall()
                if (response.isSuccessful) {
                    val body = response.body()
                    if (body != null) {
                        ApiResult.Success(body)
                    } else {
                        ApiResult.Error(response.code(), "Empty response body")
                    }
                } else {
                    val errorBody = response.errorBody()?.string() ?: "Unknown error"
                    ApiResult.Error(response.code(), errorBody)
                }
            } catch (e: javax.net.ssl.SSLException) {
                ApiResult.Exception(SecurityException("SSL/TLS error: ${e.message}", e))
            } catch (e: javax.net.ssl.SSLHandshakeException) {
                ApiResult.Exception(SecurityException("Certificate validation failed: ${e.message}", e))
            } catch (e: java.security.cert.CertificateException) {
                ApiResult.Exception(SecurityException("Invalid certificate: ${e.message}", e))
            } catch (e: Exception) {
                ApiResult.Exception(e)
            }
        }
    }
}

