package com.example.networking.example

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.networking.ApiResult
import com.example.networking.model.UserProfile
import com.example.networking.repository.UserRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

class UserViewModel : ViewModel() {

    private val userRepository = UserRepository()

    private val _usersState = MutableStateFlow<UsersUiState>(UsersUiState.Loading)
    val usersState: StateFlow<UsersUiState> = _usersState

    fun fetchUsers(page: Int = 1) {
        viewModelScope.launch {
            _usersState.value = UsersUiState.Loading
            when (val result = userRepository.getUsers(page)) {
                is ApiResult.Success -> {
                    _usersState.value = UsersUiState.Success(result.data.data)
                }
                is ApiResult.Error -> {
                    _usersState.value = UsersUiState.Error("Error ${result.code}: ${result.message}")
                }
                is ApiResult.Exception -> {
                    _usersState.value = UsersUiState.Error(
                        result.throwable.message ?: "Unknown error"
                    )
                }
            }
        }
    }

    fun fetchCurrentUser() {
        viewModelScope.launch {
            when (val result = userRepository.getCurrentUser()) {
                is ApiResult.Success -> {
                    // Handle current user
                }
                is ApiResult.Error -> {
                    // Handle error
                }
                is ApiResult.Exception -> {
                    // Handle exception
                }
            }
        }
    }
}

sealed class UsersUiState {
    object Loading : UsersUiState()
    data class Success(val users: List<UserProfile>) : UsersUiState()
    data class Error(val message: String) : UsersUiState()
}

